     1→// websockify: minimal WebSocket → TCP proxy for VNC.
     2→// Accepts WebSocket connections and tunnels binary frames to a TCP target.
     3→// Usage: websockify -addr :6080 -target localhost:5900 -url /websockify
     4→package main
     5→
     6→import (
     7→	"flag"
     8→	"log"
     9→	"net"
    10→	"net/http"
    11→
    12→	"github.com/gorilla/websocket"
    13→)
    14→
    15→var upgrader = websocket.Upgrader{
    16→	// Allow connections from any origin (auth is handled upstream by Traefik forwardAuth).
    17→	CheckOrigin: func(r *http.Request) bool { return true },
    18→}
    19→
    20→func proxy(ws *websocket.Conn, target string) {
    21→	conn, err := net.Dial("tcp", target)
    22→	if err != nil {
    23→		log.Printf("dial %s: %v", target, err)
    24→		return
    25→	}
    26→	defer conn.Close()
    27→
    28→	done := make(chan struct{}, 1)
    29→
    30→	// VNC → WebSocket (server speaks first with RFB banner)
    31→	go func() {
    32→		defer func() { done <- struct{}{} }()
    33→		buf := make([]byte, 65536)
    34→		for {
    35→			n, err := conn.Read(buf)
    36→			if n > 0 {
    37→				if werr := ws.WriteMessage(websocket.BinaryMessage, buf[:n]); werr != nil {
    38→					return
    39→				}
    40→			}
    41→			if err != nil {
    42→				return
    43→			}
    44→		}
    45→	}()
    46→
    47→	// WebSocket → VNC
    48→	for {
    49→		_, msg, err := ws.ReadMessage()
    50→		if err != nil {
    51→			break
    52→		}
    53→		if _, err := conn.Write(msg); err != nil {
    54→			break
    55→		}
    56→	}
    57→	<-done
    58→}
    59→
    60→func main() {
    61→	addr := flag.String("addr", ":6080", "listen address")
    62→	target := flag.String("target", "localhost:5900", "TCP target address (Xvnc)")
    63→	path := flag.String("url", "/websockify", "WebSocket URL path")
    64→	flag.Parse()
    65→
    66→	http.HandleFunc(*path, func(w http.ResponseWriter, r *http.Request) {
    67→		ws, err := upgrader.Upgrade(w, r, nil)
    68→		if err != nil {
    69→			log.Printf("websocket upgrade: %v", err)
    70→			return
    71→		}
    72→		defer ws.Close()
    73→		proxy(ws, *target)
    74→	})
    75→
    76→	log.Printf("websockify: listening on %s, proxying %s → %s", *addr, *path, *target)
    77→	log.Fatal(http.ListenAndServe(*addr, nil))
    78→}
    79→

